local ez = game:GetService("RunService")
local p0 = require(script.Parent.Signal)
local p1 = function() end
local p2 = {}
p2.__index = p2
function p2.new()
	return setmetatable({ _onStep = p0.new(), _onStart = p0.new(), _onComplete = p0.new() }, p2)
end
function p2:onStep(p3)
	return self._onStep:connect(p3)
end
function p2:onStart(p3)
	return self._onStart:connect(p3)
end
function p2:onComplete(p3)
	return self._onComplete:connect(p3)
end
function p2:start()
	if not self._connection then
		self._connection = ez.RenderStepped:Connect(function(eO)
			self:step(eO)
		end)
	end
end
function p2:stop()
	if self._connection then
		self._connection:Disconnect()
		self._connection = nil
	end
end
p2.destroy = p2.stop
p2.step = p1
p2.getValue = p1
p2.setGoal = p1
function p2:__tostring()
	return "Motor"
end
return p2
